9059 SelectPatternResult llvm::matchSelectPattern(Value *V, Value *&LHS, Value *&RHS,
9060                                              Instruction::CastOps *CastOp,
9061                                              unsigned Depth) {
9062   if (Depth >= MaxAnalysisRecursionDepth)
9063     return {SPF_UNKNOWN, SPNB_NA, false};
9064 
9065   SelectInst *SI = dyn_cast<SelectInst>(V);
9066   if (!SI) return {SPF_UNKNOWN, SPNB_NA, false};
9067 
9068   CmpInst *CmpI = dyn_cast<CmpInst>(SI->getCondition());
9069   if (!CmpI) return {SPF_UNKNOWN, SPNB_NA, false};
9070 
9071   Value *TrueVal = SI->getTrueValue();
9072   Value *FalseVal = SI->getFalseValue();
9073 
9074   return llvm::matchDecomposedSelectPattern(
9075       CmpI, TrueVal, FalseVal, LHS, RHS,
9076       isa<FPMathOperator>(SI) ? SI->getFastMathFlags() : FastMathFlags(),
9077       CastOp, Depth);
9078 }
