9080 SelectPatternResult llvm::matchDecomposedSelectPattern(
9081     CmpInst *CmpI, Value *TrueVal, Value *FalseVal, Value *&LHS, Value *&RHS,
9082     FastMathFlags FMF, Instruction::CastOps *CastOp, unsigned Depth) {
9083   CmpInst::Predicate Pred = CmpI->getPredicate();
9084   Value *CmpLHS = CmpI->getOperand(0);
9085   Value *CmpRHS = CmpI->getOperand(1);
9086   if (isa<FPMathOperator>(CmpI) && CmpI->hasNoNaNs())
9087     FMF.setNoNaNs();
9088 
9089   // Bail out early.
9090   if (CmpI->isEquality())
9091     return {SPF_UNKNOWN, SPNB_NA, false};
9092 
9093   // Deal with type mismatches.
9094   if (CastOp && CmpLHS->getType() != TrueVal->getType()) {
9095     if (Value *C = lookThroughCast(CmpI, TrueVal, FalseVal, CastOp)) {
9096       // If this is a potential fmin/fmax with a cast to integer, then ignore
9097       // -0.0 because there is no corresponding integer value.
9098       if (*CastOp == Instruction::FPToSI || *CastOp == Instruction::FPToUI)
9099         FMF.setNoSignedZeros();
9100       return ::matchSelectPattern(Pred, FMF, CmpLHS, CmpRHS,
9101                                   cast<CastInst>(TrueVal)->getOperand(0), C,
9102                                   LHS, RHS, Depth);
9103     }
9104     if (Value *C = lookThroughCast(CmpI, FalseVal, TrueVal, CastOp)) {
9105       // If this is a potential fmin/fmax with a cast to integer, then ignore
9106       // -0.0 because there is no corresponding integer value.
9107       if (*CastOp == Instruction::FPToSI || *CastOp == Instruction::FPToUI)
9108         FMF.setNoSignedZeros();
9109       return ::matchSelectPattern(Pred, FMF, CmpLHS, CmpRHS,
9110                                   C, cast<CastInst>(FalseVal)->getOperand(0),
9111                                   LHS, RHS, Depth);
9112     }
9113   }
9114   return ::matchSelectPattern(Pred, FMF, CmpLHS, CmpRHS, TrueVal, FalseVal,
9115                               LHS, RHS, Depth);
9116 }
