9118 CmpInst::Predicate llvm::getMinMaxPred(SelectPatternFlavor SPF, bool Ordered) {
9119   if (SPF == SPF_SMIN) return ICmpInst::ICMP_SLT;
9120   if (SPF == SPF_UMIN) return ICmpInst::ICMP_ULT;
9121   if (SPF == SPF_SMAX) return ICmpInst::ICMP_SGT;
9122   if (SPF == SPF_UMAX) return ICmpInst::ICMP_UGT;
9123   if (SPF == SPF_FMINNUM)
9124     return Ordered ? FCmpInst::FCMP_OLT : FCmpInst::FCMP_ULT;
9125   if (SPF == SPF_FMAXNUM)
9126     return Ordered ? FCmpInst::FCMP_OGT : FCmpInst::FCMP_UGT;
