9154   switch (MinMaxID) {
9155   case Intrinsic::smax: return Intrinsic::smin;
9156   case Intrinsic::smin: return Intrinsic::smax;
9157   case Intrinsic::umax: return Intrinsic::umin;
9158   case Intrinsic::umin: return Intrinsic::umax;
