9184 llvm::canConvertToMinOrMaxIntrinsic(ArrayRef<Value *> VL) {
9185   // Check if VL contains select instructions that can be folded into a min/max
9186   // vector intrinsic and return the intrinsic if it is possible.
9187   // TODO: Support floating point min/max.
9188   bool AllCmpSingleUse = true;
9189   SelectPatternResult SelectPattern;
9190   SelectPattern.Flavor = SPF_UNKNOWN;
9191   if (all_of(VL, [&SelectPattern, &AllCmpSingleUse](Value *I) {
9192         Value *LHS, *RHS;
9193         auto CurrentPattern = matchSelectPattern(I, LHS, RHS);
9194         if (!SelectPatternResult::isMinOrMax(CurrentPattern.Flavor))
9195           return false;
9196         if (SelectPattern.Flavor != SPF_UNKNOWN &&
9197             SelectPattern.Flavor != CurrentPattern.Flavor)
9198           return false;
9199         SelectPattern = CurrentPattern;
9200         AllCmpSingleUse &=
9201             match(I, m_Select(m_OneUse(m_Value()), m_Value(), m_Value()));
9202         return true;
9203       })) {
9204     switch (SelectPattern.Flavor) {
9205     case SPF_SMIN:
9206       return {Intrinsic::smin, AllCmpSingleUse};
9207     case SPF_UMIN:
9208       return {Intrinsic::umin, AllCmpSingleUse};
9209     case SPF_SMAX:
9210       return {Intrinsic::smax, AllCmpSingleUse};
9211     case SPF_UMAX:
9212       return {Intrinsic::umax, AllCmpSingleUse};
9213     case SPF_FMAXNUM:
9214       return {Intrinsic::maxnum, AllCmpSingleUse};
9215     case SPF_FMINNUM:
9216       return {Intrinsic::minnum, AllCmpSingleUse};
9217     default:
9218       llvm_unreachable("unexpected select pattern flavor");
9219     }
9220   }
9221   return {Intrinsic::not_intrinsic, false};
